name_to_id = {}
parent_dsu = []

def get_id(name):
    if name not in name_to_id:
        idx = len(name_to_id)
        name_to_id[name] = idx
        parent_dsu.append(idx)
    return name_to_id[name]

def find(i):
    root = i
    while parent_dsu[root] != root:
        root = parent_dsu[root]
    curr = i
    while curr != root:
        nxt = parent_dsu[curr]
        parent_dsu[curr] = root
        curr = nxt
    return root

def union(i, j):
    root_i = find(i)
    root_j = find(j)
    if root_i != root_j:
        parent_dsu[root_i] = root_j

