        rev_u = len(adj[v])
        rev_v = len(adj[u])
        if u == v:
            rev_v -= 1
        adj[u].append([v, 1, rev_u])
        adj[v].append([u, 1, rev_v])
        
    level = [-1] * num_nodes
    ptr = [0] * num_nodes
    
    def bfs():
        for i in range(num_nodes):
            level[i] = -1
        level[s] = 0
        queue = deque([s])
        
        while queue:
            u = queue.popleft()
            for v, cap, rev_idx in adj[u]:
                if cap > 0 and level[v] == -1:
                    level[v] = level[u] + 1
                    queue.append(v)
        return level[t] != -1

    def dfs(u, pushed):
        if pushed == 0:
            return 0
        if u == t:
            return pushed
            
        while ptr[u] < len(adj[u]):
            v, cap, rev_idx = adj[u][ptr[u]]
            if level[v] == level[u] + 1 and cap > 0:
                tr = dfs(v, min(pushed, cap))
                if tr > 0:
                    adj[u][ptr[u]][1] -= tr
                    adj[v][rev_idx][1] += tr
                    return tr
            ptr[u] += 1
            
        return 0

    max_flow = 0
    INF = float('inf')
    
    while bfs():
        for i in range(num_nodes):
            ptr[i] = 0
        while True:
            pushed = dfs(s, INF)
            if pushed == 0:
                break
            max_flow += pushed
            
    return max_flow

