#include <algorithm>
#include <iostream>
#include <queue>
#include <stack>
#include <unordered_map>
#include <vector>

using namespace std;

const int INF = 1e9;

class DSU {
 private:
  vector<int> parent, rank;

 public:
  DSU() {}

  DSU(int n) {
    parent.resize(n);
    rank.assign(n, 0);
    for (int i = 0; i < n; i++) {
      parent[i] = i;
    }
  }

  int find(int v) {
    if (v == parent[v]) {
      return v;
    }

    return parent[v] = find(parent[v]);
  }

  void unite(int x, int y) {
    int root_x = find(x);
    int root_y = find(y);

    if (root_x == root_y) {
      return;
    }

    if (rank[root_x] < rank[root_y]) {
      parent[root_x] = root_y;
    } else if (rank[root_x] > rank[root_y]) {
      parent[root_y] = root_x;
    } else {
      parent[root_y] = root_x;
      rank[root_x] += 1;
    }
  }

  bool connected(int x, int y) { return find(x) == find(y); }
};

struct Edge {
  int to;
  int weight;
  int back;
};

struct State {
  int v;
  int pushed;
};

int get_id(unordered_map<string, int>& ids, const string& s, int& total) {
  auto it = ids.find(s);

  if (it != ids.end()) {
    return it->second;
  }

  ids[s] = total++;
  return total - 1;
}

void add_dir_edge(vector<vector<Edge>>& g, int s, int f, int w) {
  g[s].push_back({f, w, (int)g[f].size()});
  g[f].push_back({s, 0, (int)g[s].size() - 1});
}

void add_undir_edge(vector<vector<Edge>>& g, int u, int v, int w) {
  add_dir_edge(g, u, v, w);
  add_dir_edge(g, v, u, w);
}

bool bfs(vector<vector<Edge>>& g, vector<int>& level, int start_v,
         int finish_v) {
  int n = g.size();
  queue<int> q;
  q.push(start_v);
  fill(level.begin(), level.end(), -1);
  level[start_v] = 0;

  while (!q.empty()) {
    int curr_v = q.front();
    q.pop();

    for (const auto& e : g[curr_v]) {
      if (level[e.to] == -1 && e.weight != 0) {
        level[e.to] = level[curr_v] + 1;
        q.push(e.to);
      }
    }
  }

  return level[finish_v] != -1;
}

int dfs(vector<vector<Edge>>& g, vector<int>& level, vector<int>& ptr,
        int start_v, int finish_v) {
  int n = g.size();
  stack<State> st;
  vector<int> v_path, e_path;
  st.push({start_v, INF});
  v_path.push_back(start_v);

  while (!st.empty()) {
    int curr_v = st.top().v;
    int pushed = st.top().pushed;

    if (curr_v == finish_v) {
      for (int i = 0; i < e_path.size(); i++) {
        int u = v_path[i];
        int idx = e_path[i];
        int to = g[u][idx].to;
        int back = g[u][idx].back;

        g[u][idx].weight -= pushed;
        g[to][back].weight += pushed;
      }

      return pushed;
    }

    bool advanced = false;

    for (int next_v = ptr[curr_v]; next_v < g[curr_v].size(); next_v++) {
      int to = g[curr_v][next_v].to;
      if (level[to] == level[curr_v] + 1 && g[curr_v][next_v].weight != 0) {
        ptr[curr_v] = next_v + 1;
        st.push({to, min(pushed, g[curr_v][next_v].weight)});
        v_path.push_back(to);
        e_path.push_back(next_v);
        advanced = true;
        break;
      }
    }

    if (advanced) {
      continue;
    }

    st.pop();
    v_path.pop_back();

    if (!e_path.empty()) {
      e_path.pop_back();
    }

    if (!st.empty()) {
      level[curr_v] = -1;
    }
  }

  return 0;
}

long long dinic(vector<vector<Edge>>& g, int start_v, int finish_v) {
  int n = g.size();
  long long flow = 0;
  vector<int> level(n), ptr(n);

  while (bfs(g, level, start_v, finish_v)) {
    fill(ptr.begin(), ptr.end(), 0);

    while (true) {
      int pushed = dfs(g, level, ptr, start_v, finish_v);

      if (pushed == 0) {
        break;
      }

      flow += pushed;
    }
  }

  return flow;
}

int main() {
  int n, m, k;
  unordered_map<string, int> ids;
  DSU dsu;
  vector<pair<int, int>> edges;
  int total = 0;
  string a, b;
  int u, v;
  vector<vector<Edge>> g;
  cin >> n >> m >> k;
  ids.reserve(n);
  dsu = DSU(n);
  edges.reserve(m);

  for (int i = 0; i < m; i++) {
    cin >> a >> b;
    u = get_id(ids, a, total);
    v = get_id(ids, b, total);
    edges.emplace_back(u, v);
    dsu.unite(u, v);
  }

  for (int i = 0; i < k; i++) {
    cin >> a >> b;
    int s = get_id(ids, a, total);
    int f = get_id(ids, b, total);

    if (s == f) {
      cout << 0 << endl;
      continue;
    }

    if (!dsu.connected(s, f)) {
      cout << 0 << endl;
      continue;
    }

    g.clear();
    g.resize(total);

    for (int j = 0; j < m; j++) {
      u = edges[j].first;
      v = edges[j].second;
      add_undir_edge(g, u, v, 1);
    }

    cout << dinic(g, s, f) << endl;
  }
  return 0;
}

